import React, { useState, useEffect } from 'react';
import { api } from '../services/api';

interface Animal {
  id: number;
  identificador_unico: string;
  nombre: string;
  sexo: string;
  raza_nombre: string;
  fecha_nacimiento: string;
  padre_id?: number;
  madre_id?: number;
  generation?: number;
  padre?: Animal;
  madre?: Animal;
}

interface GeneticIndices {
  fertilidad: number;
  habilidad_materna: number;
  conversion_alimenticia: number;
  ganancia_diaria: number;
  indice_seleccion: number;
}

interface MatingRecommendation {
  verraco: Animal & { indice_seleccion: number };
  consanguinity: string;
  score: string;
  recommendation: string;
}

const Genealogy: React.FC = () => {
  const [selectedAnimal, setSelectedAnimal] = useState<number | null>(null);
  const [genealogyTree, setGenealogyTree] = useState<Animal | null>(null);
  const [geneticIndices, setGeneticIndices] = useState<GeneticIndices | null>(null);
  const [matingRecommendations, setMatingRecommendations] = useState<MatingRecommendation[]>([]);
  const [reproductors, setReproductors] = useState<Animal[]>([]);
  const [consanguinityCheck, setConsanguinityCheck] = useState<{
    animal1: number | null;
    animal2: number | null;
    result: any;
  }>({ animal1: null, animal2: null, result: null });
  const [activeTab, setActiveTab] = useState<'tree' | 'indices' | 'mating' | 'consanguinity'>('tree');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    loadReproductors();
  }, []);

  const loadReproductors = async () => {
    try {
      const response = await api.get('/animals?categoria=reproductor&estado=activo');
      setReproductors(response.data);
    } catch (error) {
      console.error('Error cargando reproductores:', error);
    }
  };

  const loadGenealogyTree = async (animalId: number) => {
    setLoading(true);
    try {
      const response = await api.get(`/genealogy/tree/${animalId}?generations=4`);
      setGenealogyTree(response.data);
    } catch (error) {
      console.error('Error cargando árbol genealógico:', error);
    } finally {
      setLoading(false);
    }
  };

  const loadGeneticIndices = async (animalId: number) => {
    setLoading(true);
    try {
      const response = await api.get(`/genealogy/indices/${animalId}`);
      setGeneticIndices(response.data);
    } catch (error) {
      console.error('Error cargando índices genéticos:', error);
    } finally {
      setLoading(false);
    }
  };

  const loadMatingRecommendations = async (cerdaId: number) => {
    setLoading(true);
    try {
      const response = await api.get(`/genealogy/mating-recommendations/${cerdaId}`);
      setMatingRecommendations(response.data);
    } catch (error) {
      console.error('Error cargando recomendaciones:', error);
    } finally {
      setLoading(false);
    }
  };

  const checkConsanguinity = async () => {
    if (!consanguinityCheck.animal1 || !consanguinityCheck.animal2) return;

    setLoading(true);
    try {
      const response = await api.get(`/genealogy/consanguinity/${consanguinityCheck.animal1}/${consanguinityCheck.animal2}`);
      setConsanguinityCheck(prev => ({ ...prev, result: response.data }));
    } catch (error) {
      console.error('Error calculando consanguinidad:', error);
    } finally {
      setLoading(false);
    }
  };

  const recalculateIndices = async (animalId: number) => {
    setLoading(true);
    try {
      await api.post(`/genealogy/indices/${animalId}/calculate`);
      await loadGeneticIndices(animalId);
    } catch (error) {
      console.error('Error recalculando índices:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleAnimalSelect = (animalId: number) => {
    setSelectedAnimal(animalId);
    if (activeTab === 'tree') {
      loadGenealogyTree(animalId);
    } else if (activeTab === 'indices') {
      loadGeneticIndices(animalId);
    } else if (activeTab === 'mating') {
      const animal = reproductors.find(r => r.id === animalId);
      if (animal && animal.sexo === 'hembra') {
        loadMatingRecommendations(animalId);
      }
    }
  };

  const renderAnimalCard = (animal: Animal, generation: number = 0) => {
    if (!animal) return null;

    return (
      <div 
        className={`animal-card generation-${generation}`}
        style={{ 
          marginLeft: `${generation * 20}px`,
          border: '1px solid #ddd',
          padding: '10px',
          margin: '5px',
          borderRadius: '5px',
          backgroundColor: animal.sexo === 'macho' ? '#e3f2fd' : '#fce4ec'
        }}
      >
        <div className="animal-info">
          <strong>{animal.identificador_unico}</strong>
          {animal.nombre && <span> - {animal.nombre}</span>}
          <br />
          <small>
            {animal.sexo === 'macho' ? '♂' : '♀'} {animal.raza_nombre}
            <br />
            Nacimiento: {new Date(animal.fecha_nacimiento).toLocaleDateString()}
          </small>
        </div>

        {(animal.padre || animal.madre) && (
          <div className="parents" style={{ marginTop: '10px' }}>
            {animal.padre && (
              <div>
                <strong>Padre:</strong>
                {renderAnimalCard(animal.padre, generation + 1)}
              </div>
            )}
            {animal.madre && (
              <div>
                <strong>Madre:</strong>
                {renderAnimalCard(animal.madre, generation + 1)}
              </div>
            )}
          </div>
        )}
      </div>
    );
  };

  const renderGeneticIndices = () => {
    if (!geneticIndices) return <p>Selecciona un animal para ver sus índices genéticos</p>;

    return (
      <div className="genetic-indices">
        <div className="indices-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '15px' }}>
          <div className="index-card">
            <h4>Fertilidad</h4>
            <div className="index-value">{geneticIndices.fertilidad.toFixed(1)}%</div>
            <div className="index-bar">
              <div 
                className="index-fill" 
                style={{ 
                  width: `${geneticIndices.fertilidad}%`, 
                  backgroundColor: geneticIndices.fertilidad > 80 ? '#4caf50' : geneticIndices.fertilidad > 60 ? '#ff9800' : '#f44336',
                  height: '8px',
                  borderRadius: '4px'
                }}
              ></div>
            </div>
          </div>

          <div className="index-card">
            <h4>Habilidad Materna</h4>
            <div className="index-value">{geneticIndices.habilidad_materna.toFixed(1)}%</div>
            <div className="index-bar">
              <div 
                className="index-fill" 
                style={{ 
                  width: `${geneticIndices.habilidad_materna}%`, 
                  backgroundColor: geneticIndices.habilidad_materna > 80 ? '#4caf50' : geneticIndices.habilidad_materna > 60 ? '#ff9800' : '#f44336',
                  height: '8px',
                  borderRadius: '4px'
                }}
              ></div>
            </div>
          </div>

          <div className="index-card">
            <h4>Conversión Alimenticia</h4>
            <div className="index-value">{geneticIndices.conversion_alimenticia.toFixed(1)}%</div>
            <div className="index-bar">
              <div 
                className="index-fill" 
                style={{ 
                  width: `${geneticIndices.conversion_alimenticia}%`, 
                  backgroundColor: geneticIndices.conversion_alimenticia > 80 ? '#4caf50' : geneticIndices.conversion_alimenticia > 60 ? '#ff9800' : '#f44336',
                  height: '8px',
                  borderRadius: '4px'
                }}
              ></div>
            </div>
          </div>

          <div className="index-card">
            <h4>Ganancia Diaria</h4>
            <div className="index-value">{geneticIndices.ganancia_diaria.toFixed(1)}%</div>
            <div className="index-bar">
              <div 
                className="index-fill" 
                style={{ 
                  width: `${geneticIndices.ganancia_diaria}%`, 
                  backgroundColor: geneticIndices.ganancia_diaria > 80 ? '#4caf50' : geneticIndices.ganancia_diaria > 60 ? '#ff9800' : '#f44336',
                  height: '8px',
                  borderRadius: '4px'
                }}
              ></div>
            </div>
          </div>
        </div>

        <div className="overall-index" style={{ marginTop: '20px', textAlign: 'center' }}>
          <h3>Índice de Selección General</h3>
          <div style={{ fontSize: '2em', fontWeight: 'bold', color: geneticIndices.indice_seleccion > 80 ? '#4caf50' : geneticIndices.indice_seleccion > 60 ? '#ff9800' : '#f44336' }}>
            {geneticIndices.indice_seleccion.toFixed(1)}%
          </div>
          <button 
            onClick={() => selectedAnimal && recalculateIndices(selectedAnimal)}
            disabled={loading}
            style={{ marginTop: '10px', padding: '8px 16px', backgroundColor: '#2196f3', color: 'white', border: 'none', borderRadius: '4px' }}
          >
            {loading ? 'Recalculando...' : 'Recalcular Índices'}
          </button>
        </div>
      </div>
    );
  };

  const renderMatingRecommendations = () => {
    if (matingRecommendations.length === 0) {
      return <p>Selecciona una cerda reproductora para ver recomendaciones de apareamiento</p>;
    }

    return (
      <div className="mating-recommendations">
        <h3>Recomendaciones de Apareamiento</h3>
        <div className="recommendations-list">
          {matingRecommendations.map((rec, index) => (
            <div 
              key={rec.verraco.id} 
              className="recommendation-card"
              style={{
                border: '1px solid #ddd',
                padding: '15px',
                margin: '10px 0',
                borderRadius: '8px',
                backgroundColor: rec.recommendation === 'Excelente' ? '#e8f5e8' : rec.recommendation === 'Bueno' ? '#fff3e0' : rec.recommendation === 'No recomendado' ? '#ffebee' : '#f5f5f5'
              }}
            >
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                  <h4>{rec.verraco.identificador_unico} - {rec.verraco.nombre}</h4>
                  <p>Raza: {rec.verraco.raza_nombre}</p>
                  <p>Índice de Selección: {rec.verraco.indice_seleccion?.toFixed(1) || 'N/A'}%</p>
                </div>
                <div style={{ textAlign: 'right' }}>
                  <div style={{ fontSize: '1.2em', fontWeight: 'bold' }}>
                    Score: {rec.score}%
                  </div>
                  <div style={{ 
                    color: rec.recommendation === 'Excelente' ? '#4caf50' : rec.recommendation === 'Bueno' ? '#ff9800' : rec.recommendation === 'No recomendado' ? '#f44336' : '#666',
                    fontWeight: 'bold'
                  }}>
                    {rec.recommendation}
                  </div>
                  <div style={{ fontSize: '0.9em', color: '#666' }}>
                    Consanguinidad: {rec.consanguinity}%
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  const renderConsanguinityCheck = () => {
    return (
      <div className="consanguinity-check">
        <h3>Verificación de Consanguinidad</h3>
        <div style={{ display: 'flex', gap: '20px', alignItems: 'center', marginBottom: '20px' }}>
          <div>
            <label>Animal 1:</label>
            <select 
              value={consanguinityCheck.animal1 || ''} 
              onChange={(e) => setConsanguinityCheck(prev => ({ ...prev, animal1: parseInt(e.target.value) }))}
              style={{ marginLeft: '10px', padding: '5px' }}
            >
              <option value="">Seleccionar...</option>
              {reproductors.map(animal => (
                <option key={animal.id} value={animal.id}>
                  {animal.identificador_unico} - {animal.nombre}
                </option>
              ))}
            </select>
          </div>

          <div>
            <label>Animal 2:</label>
            <select 
              value={consanguinityCheck.animal2 || ''} 
              onChange={(e) => setConsanguinityCheck(prev => ({ ...prev, animal2: parseInt(e.target.value) }))}
              style={{ marginLeft: '10px', padding: '5px' }}
            >
              <option value="">Seleccionar...</option>
              {reproductors.map(animal => (
                <option key={animal.id} value={animal.id}>
                  {animal.identificador_unico} - {animal.nombre}
                </option>
              ))}
            </select>
          </div>

          <button 
            onClick={checkConsanguinity}
            disabled={!consanguinityCheck.animal1 || !consanguinityCheck.animal2 || loading}
            style={{ padding: '8px 16px', backgroundColor: '#2196f3', color: 'white', border: 'none', borderRadius: '4px' }}
          >
            {loading ? 'Calculando...' : 'Verificar'}
          </button>
        </div>

        {consanguinityCheck.result && (
          <div className="consanguinity-result" style={{
            padding: '20px',
            border: '2px solid',
            borderColor: consanguinityCheck.result.risk === 'alto' ? '#f44336' : consanguinityCheck.result.risk === 'medio' ? '#ff9800' : '#4caf50',
            borderRadius: '8px',
            backgroundColor: consanguinityCheck.result.risk === 'alto' ? '#ffebee' : consanguinityCheck.result.risk === 'medio' ? '#fff3e0' : '#e8f5e8'
          }}>
            <h4>Resultado del Análisis</h4>
            <p><strong>Coeficiente de Consanguinidad:</strong> {consanguinityCheck.result.percentage}%</p>
            <p><strong>Nivel de Riesgo:</strong> 
              <span style={{ 
                color: consanguinityCheck.result.risk === 'alto' ? '#f44336' : consanguinityCheck.result.risk === 'medio' ? '#ff9800' : '#4caf50',
                fontWeight: 'bold',
                marginLeft: '5px'
              }}>
                {consanguinityCheck.result.risk.toUpperCase()}
              </span>
            </p>
            <p><strong>Recomendación:</strong> {consanguinityCheck.result.recommendation}</p>

            {consanguinityCheck.result.risk === 'alto' && (
              <div style={{ marginTop: '10px', padding: '10px', backgroundColor: '#ffcdd2', borderRadius: '4px' }}>
                ⚠️ <strong>Advertencia:</strong> Este apareamiento presenta alto riesgo de consanguinidad. 
                Se recomienda buscar alternativas con menor parentesco.
              </div>
            )}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="fade-in" style={{ padding: '20px', maxWidth: '1400px', margin: '0 auto' }}>
      <div className="card-header" style={{ background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', color: 'white', borderRadius: '12px 12px 0 0', padding: '25px' }}>
        <div>
          <h1 className="card-title" style={{ fontSize: '28px', fontWeight: '700', margin: '0 0 8px 0' }}>🧬 Genealogía y Genética</h1>
          <p style={{ margin: 0, opacity: 0.9, fontSize: '16px' }}>Análisis genético avanzado y recomendaciones de apareamiento</p>
        </div>

      </div>

      <div className="card" style={{ borderRadius: '0 0 12px 12px', boxShadow: '0 10px 30px rgba(0,0,0,0.1)' }}>
        <div style={{ padding: '25px' }}>
          <div className="form-group" style={{ marginBottom: '25px' }}>
            <label style={{ display: 'block', fontWeight: '600', marginBottom: '8px', color: '#2c3e50' }}>🐷 Seleccionar Animal Reproductor</label>
            <select 
              value={selectedAnimal || ''} 
              onChange={(e) => handleAnimalSelect(parseInt(e.target.value))}
              style={{ 
                width: '100%', 
                maxWidth: '400px',
                padding: '12px 16px', 
                border: '2px solid #e1e8ed',
                borderRadius: '8px',
                fontSize: '16px',
                backgroundColor: 'white',
                transition: 'all 0.3s ease'
              }}
            >
              <option value="">Seleccionar reproductor...</option>
              {reproductors.map(animal => (
                <option key={animal.id} value={animal.id}>
                  {animal.sexo === 'macho' ? '♂' : '♀'} {animal.identificador_unico} - {animal.nombre}
                </option>
              ))}
            </select>
          </div>

          <div className="tab-container" style={{ marginBottom: '25px' }}>
            {[
              { key: 'tree', label: '🌳 Árbol Genealógico', desc: 'Visualizar ancestros' },
              { key: 'indices', label: '📊 Índices Genéticos', desc: 'Métricas de rendimiento' },
              { key: 'mating', label: '💕 Recomendaciones', desc: 'Mejores apareamientos' },
              { key: 'consanguinity', label: '🔍 Consanguinidad', desc: 'Verificar parentesco' }
            ].map(tab => (
              <button
                key={tab.key}
                onClick={() => setActiveTab(tab.key as any)}
                className={`tab-button ${activeTab === tab.key ? 'active' : ''}`}
                style={{
                  padding: '15px 20px',
                  margin: '0 8px 8px 0',
                  border: 'none',
                  borderRadius: '10px',
                  backgroundColor: activeTab === tab.key ? '#667eea' : '#f8f9fa',
                  color: activeTab === tab.key ? 'white' : '#495057',
                  cursor: 'pointer',
                  transition: 'all 0.3s ease',
                  fontWeight: '600',
                  boxShadow: activeTab === tab.key ? '0 4px 15px rgba(102, 126, 234, 0.3)' : '0 2px 8px rgba(0,0,0,0.1)',
                  transform: activeTab === tab.key ? 'translateY(-2px)' : 'none'
                }}
              >
                <div>{tab.label}</div>
                <div style={{ fontSize: '12px', opacity: 0.8, marginTop: '2px' }}>{tab.desc}</div>
              </button>
            ))}
          </div>

          <div className="genealogy-content">
            {loading && (
              <div style={{ textAlign: 'center', padding: '40px' }}>
                <div style={{ fontSize: '48px', marginBottom: '16px' }}>🔄</div>
                <div style={{ fontSize: '18px', color: '#667eea' }}>Analizando datos genéticos...</div>
              </div>
            )}

            {activeTab === 'tree' && (
              <div className="genealogy-tree">
                <div style={{ background: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)', padding: '20px', borderRadius: '12px', marginBottom: '20px' }}>
                  <h3 style={{ color: 'white', margin: '0 0 8px 0', fontSize: '22px' }}>🌳 Árbol Genealógico</h3>
                  <p style={{ color: 'rgba(255,255,255,0.9)', margin: 0 }}>Explora hasta 4 generaciones de ancestros</p>
                </div>
                {genealogyTree ? (
                  <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '12px', overflow: 'auto' }}>
                    {renderAnimalCard(genealogyTree)}
                  </div>
                ) : (
                  <div className="empty-state" style={{ textAlign: 'center', padding: '60px 20px' }}>
                    <div style={{ fontSize: '64px', marginBottom: '16px' }}>🌳</div>
                    <h3 style={{ color: '#495057', marginBottom: '8px' }}>Árbol Genealógico</h3>
                    <p style={{ color: '#6c757d' }}>Selecciona un animal reproductor para visualizar su genealogía</p>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'indices' && renderGeneticIndices()}
            {activeTab === 'mating' && renderMatingRecommendations()}
            {activeTab === 'consanguinity' && renderConsanguinityCheck()}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Genealogy;
